import React, { useCallback, useEffect } from "react";
import { MultiSelect } from "@lmb/kitsconcertomobile";
import KitsContainer from "../../Helpers/FormContainer";
import type { IMultiSelect } from "@lmb/kitsconcerto-types";
import { ClHelper } from "../../Helpers/Functions";
import { checkKeys } from "../helper";
import { useSelectBase } from "../hooks/useSelectBase";

const KitsMultiSelect = ({ className, ref, ...props }: IMultiSelect) => {
    const {
        id,
        disabled,
        isFloatedLabel,
        rightAddon,
        leftAddon,
        required,
        errors,
        invalid,
        placeholder,
        virtualScroll,
        label,
        inputSize,
        helperText,
        emptyFilterMessage,
        selectionLimit,
        localProps,
        hideError,
        withFilter,
        loading,
        showClear,
        valueMode,
    } = props;

    const { list, keys, onChange, selectedValue, childrenKey, labelKey, valueKey } = useSelectBase();

    useEffect(() => {
        checkKeys(list, labelKey, !childrenKey ? valueKey : undefined);
    }, [list]);

    const ClState = ClHelper({
        inputSize: inputSize ?? "",
        isChecked: false,
        isInvalid: !!invalid,
        isDisabled: !!disabled,
    });

    const handleChange = useCallback((e: any, items: any) => {
        if (selectionLimit && Array.isArray(e?.target?.value) && e.target.value.length > selectionLimit) {
            return;
        }
        onChange && onChange(e, items);
    }, [selectionLimit, onChange]);

    return (
        <KitsContainer
            id={id}
            inputSize={inputSize}
            isFloatedLabel={isFloatedLabel}
            rightAddon={rightAddon}
            leftAddon={leftAddon}
            required={required}
            hideError={hideError}
            errors={errors}
            helperText={helperText}
            invalid={invalid}
            label={label}
        >
            <MultiSelect
                emptyFilterMessage={emptyFilterMessage}
                value={selectedValue}
                onChange={handleChange}
                disabled={disabled}
                loading={loading}
                showClear={showClear}
                options={typeof list !== "function" ? list : []}
                placeholder={placeholder}
                {...keys}
                filter={withFilter !== false}
                selectionLimit={selectionLimit}
                display={valueMode === "comma" ? "comma" : (localProps?.maxSelectedLabels ? undefined : "chip")}
                maxSelectedLabels={selectionLimit ?? localProps?.maxSelectedLabels ?? 10}
                className={`w-full ${ClState}`}
                {...(localProps ? localProps : {})}
            />
        </KitsContainer>
    );
}

KitsMultiSelect.displayName = "MultiSelect";
export default KitsMultiSelect;
